    function isSpecial(num) {
        const s = num.toString();
        // Check palindrome
        if (s !== s.split('').reverse().join('')) return false;
        // Check digit counts
        const count = {};
        for (const c of s) {
            const digit = parseInt(c, 10);
            if (digit < 1 || digit > 9) return false;
            count[digit] = (count[digit] || 0) + 1;
        }
        for (const [digit, cnt] of Object.entries(count)) {
            if (parseInt(digit, 10) !== cnt) return false;
        }
        return true;
    }

    let candidate = n + 1;
    while (true) {
        if (isSpecial(candidate)) {
            return candidate;
        }
        candidate++;
    }
}

